import { motion } from "framer-motion";
import { Sun, CheckSquare, Mail } from "lucide-react";

export interface IntentChip {
  id: string;
  label: string;
  description: string;
  icon: "sun" | "check" | "mail";
  templateId: string;
}

export interface IntentChipsProps {
  intents?: IntentChip[];
  onSelect?: (intent: IntentChip) => void;
}

const DEFAULT_INTENTS: IntentChip[] = [
  {
    id: "summarize-day",
    label: "Summarize my day",
    description: "Get a structured daily plan from your calendar and emails",
    icon: "sun",
    templateId: "daily_command_brief",
  },
  {
    id: "notes-to-tasks",
    label: "Turn notes into tasks",
    description: "Extract actionable tasks from meeting notes",
    icon: "check",
    templateId: "meeting_to_tasks",
  },
  {
    id: "draft-responses",
    label: "Draft email responses",
    description: "Create thoughtful replies to important emails",
    icon: "mail",
    templateId: "inbox_triage",
  },
];

const ICON_MAP: Record<string, React.ReactNode> = {
  sun: <Sun size={20} className="text-accent" />,
  check: <CheckSquare size={20} className="text-accent" />,
  mail: <Mail size={20} className="text-accent" />,
};

export function IntentChips({ intents = DEFAULT_INTENTS, onSelect }: IntentChipsProps) {
  return (
    <div className="flex flex-wrap gap-3">
      {intents.map((intent, index) => (
        <motion.button
          key={intent.id}
          initial={{ opacity: 0, y: 8 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ delay: index * 0.1, duration: 0.2 }}
          onClick={() => onSelect?.(intent)}
          className="group flex items-center gap-2.5 rounded-xl border border-border bg-[#161a30]/60 px-4 py-3 text-sm transition-all duration-200 hover:border-accent/40 hover:bg-[#1a1f40]/80 hover:shadow-[0_0_20px_rgba(79,140,255,0.15)] focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-accent/50"
        >
          <span className="flex h-9 w-9 items-center justify-center rounded-lg bg-accent/10 transition-colors group-hover:bg-accent/20">
            {ICON_MAP[intent.icon]}
          </span>
          <div className="text-left">
            <div className="font-medium text-white transition-colors group-hover:text-white">
              {intent.label}
            </div>
            <div className="text-xs text-muted">{intent.description}</div>
          </div>
        </motion.button>
      ))}
    </div>
  );
}

export function IntentChipsSkeleton() {
  return (
    <div className="flex flex-wrap gap-3">
      {[1, 2, 3].map((i) => (
        <div
          key={i}
          className="flex items-center gap-2.5 rounded-xl border border-border bg-[#161a30]/60 px-4 py-3"
        >
          <div className="h-9 w-9 rounded-lg bg-surface-raised" />
          <div className="space-y-1.5">
            <div className="h-4 w-32 rounded bg-surface-raised" />
            <div className="h-3 w-40 rounded bg-surface-raised" />
          </div>
        </div>
      ))}
    </div>
  );
}

import { motion } from "framer-motion";
import { Zap, Clock, Coins, ChevronRight } from "lucide-react";
import { Card, CardHeader, CardTitle, CardDescription, CardContent, CardFooter } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";

export interface AutomationCardProps {
  id: string;
  name: string;
  description: string;
  outcome: string;
  setupTime: string;
  runFrequency: string;
  costPerRun: string;
  requiredTools: { name: string; connected: boolean }[];
  onConfigure?: () => void;
  variant?: "recommended" | "installed";
  status?: "active" | "paused";
}

export function AutomationCard({
  name,
  description,
  outcome,
  setupTime,
  runFrequency,
  costPerRun,
  requiredTools,
  onConfigure,
  variant = "recommended",
  status,
}: AutomationCardProps) {
  const allToolsConnected = requiredTools.every((t) => t.connected);

  return (
    <Card className="group relative overflow-hidden border-border bg-gradient-to-b from-[#1a1f40]/60 to-[#161a30]/60 transition-all duration-200 hover:border-accent/40 hover:shadow-[0_0_30px_rgba(79,140,255,0.15)]">
      {variant === "recommended" && (
        <div className="absolute -right-8 -top-8 h-24 w-24 rounded-full bg-accent/5 blur-3xl" />
      )}

      <CardHeader className="relative pb-2">
        <div className="flex items-start justify-between">
          <div className="flex items-center gap-2">
            <div className="flex h-10 w-10 items-center justify-center rounded-xl bg-accent/10 text-accent">
              <Zap size={20} />
            </div>
            <div>
              <CardTitle className="text-base font-medium text-white">{name}</CardTitle>
              {status && (
                <Badge
                  variant={status === "active" ? "success" : "warning"}
                  className="mt-1"
                >
                  {status === "active" ? "Active" : "Paused"}
                </Badge>
              )}
            </div>
          </div>
        </div>
      </CardHeader>

      <CardContent className="relative space-y-3">
        <div>
          <p className="text-sm text-muted">{outcome}</p>
        </div>

        <div className="flex flex-wrap gap-3 text-xs text-muted">
          <div className="flex items-center gap-1">
            <Clock size={12} />
            <span>Setup: {setupTime}</span>
          </div>
          <div className="flex items-center gap-1">
            <Coins size={12} />
            <span>{costPerRun}</span>
          </div>
          <div className="text-muted-foreground">•</div>
          <div>{runFrequency}</div>
        </div>

        <div className="space-y-1.5">
          <p className="text-xs font-medium text-muted">Required tools</p>
          <div className="flex flex-wrap gap-1.5">
            {requiredTools.map((tool) => (
              <Badge
                key={tool.name}
                variant={tool.connected ? "success" : "default"}
              >
                {tool.connected ? "✓" : "○"} {tool.name}
              </Badge>
            ))}
          </div>
        </div>
      </CardContent>

      <CardFooter className="relative">
        {variant === "recommended" ? (
          <Button
            variant="primary"
            size="default"
            className="w-full"
            onClick={onConfigure}
            disabled={!allToolsConnected}
          >
            Configure
            <ChevronRight size={16} />
          </Button>
        ) : (
          <Button
            variant="default"
            size="default"
            className="w-full"
            onClick={onConfigure}
          >
            {status === "paused" ? "Resume" : "Manage"}
          </Button>
        )}
      </CardFooter>
    </Card>
  );
}

export function AutomationCardSkeleton() {
  return (
    <Card className="border-border bg-gradient-to-b from-[#1a1f40]/60 to-[#161a30]/60">
      <CardHeader className="pb-2">
        <div className="flex items-center gap-2">
          <div className="h-10 w-10 rounded-xl bg-surface-raised" />
          <div className="space-y-1.5">
            <div className="h-4 w-32 rounded bg-surface-raised" />
            <div className="h-3 w-16 rounded bg-surface-raised" />
          </div>
        </div>
      </CardHeader>
      <CardContent className="space-y-3">
        <div className="h-3 w-full rounded bg-surface-raised" />
        <div className="flex gap-2">
          <div className="h-3 w-20 rounded bg-surface-raised" />
          <div className="h-3 w-16 rounded bg-surface-raised" />
          <div className="h-3 w-24 rounded bg-surface-raised" />
        </div>
        <div className="space-y-1.5">
          <div className="h-2 w-24 rounded bg-surface-raised" />
          <div className="flex gap-1.5">
            <div className="h-5 w-20 rounded-full bg-surface-raised" />
            <div className="h-5 w-24 rounded-full bg-surface-raised" />
          </div>
        </div>
      </CardContent>
      <CardFooter>
        <div className="h-9 w-full rounded bg-surface-raised" />
      </CardFooter>
    </Card>
  );
}

import { useState } from "react";
import { motion } from "framer-motion";
import { Clock, Coins, Shield, AlertTriangle, ChevronRight, ArrowLeft } from "lucide-react";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { Card, CardContent } from "@/components/ui/card";

export interface PreviewSample {
  title: string;
  content: string;
  type: "email" | "document" | "notification" | "tasks";
}

export interface PreviewSchedule {
  frequency: string;
  nextRun: string;
  timezone?: string;
}

export interface PreviewScreenProps {
  automationName: string;
  sample: PreviewSample;
  schedule: PreviewSchedule;
  costPerRun: string;
  requiresApproval?: boolean;
  onBack?: () => void;
  onActivate?: () => void;
  isLoading?: boolean;
}

export function PreviewScreen({
  automationName,
  sample,
  schedule,
  costPerRun,
  requiresApproval = false,
  onBack,
  onActivate,
  isLoading = false,
}: PreviewScreenProps) {
  const [isActivating, setIsActivating] = useState(false);

  const handleActivate = () => {
    setIsActivating(true);
    onActivate?.();
  };

  if (isLoading) {
    return <PreviewScreenSkeleton />;
  }

  return (
    <motion.div
      initial={{ opacity: 0, y: 16 }}
      animate={{ opacity: 1, y: 0 }}
      transition={{ duration: 0.3 }}
      className="space-y-6"
    >
      {/* Header */}
      <div className="flex items-center gap-4">
        <Button variant="ghost" size="icon" onClick={onBack}>
          <ArrowLeft size={18} />
        </Button>
        <div>
          <h2 className="text-lg font-medium text-white">Preview: {automationName}</h2>
          <p className="text-sm text-muted">Review before activating</p>
        </div>
      </div>

      {/* Sample Output Card */}
      <Card className="border-border bg-gradient-to-b from-[#1a1f40]/60 to-[#161a30]/60">
        <div className="border-b border-border bg-accent/10 px-4 py-2">
          <div className="flex items-center gap-2">
            <Shield size={14} className="text-accent" />
            <span className="text-xs font-semibold uppercase tracking-wider text-accent">
              This is a sample of what you&apos;ll receive
            </span>
          </div>
        </div>
        <CardContent className="p-4">
          <div className="rounded-lg border border-border bg-[#0f1117] p-4 font-mono text-sm">
            {sample.type === "email" && (
              <div className="space-y-3">
                <div className="border-b border-border pb-2">
                  <div className="text-xs text-muted">Subject:</div>
                  <div className="text-white">{sample.title}</div>
                </div>
                <div className="whitespace-pre-wrap text-text">{sample.content}</div>
              </div>
            )}
            {sample.type === "document" && (
              <div className="space-y-3">
                <h3 className="text-base font-medium text-white">{sample.title}</h3>
                <div className="whitespace-pre-wrap text-text">{sample.content}</div>
              </div>
            )}
            {sample.type === "tasks" && (
              <div className="space-y-3">
                <h3 className="text-base font-medium text-white">{sample.title}</h3>
                <div className="space-y-2">
                  {sample.content.split("\n").map((line, i) => (
                    <div key={i} className="flex items-start gap-2 text-text">
                      <div className="mt-1 h-1.5 w-1.5 rounded-full bg-accent" />
                      <span>{line}</span>
                    </div>
                  ))}
                </div>
              </div>
            )}
            {sample.type === "notification" && (
              <div className="space-y-2">
                <div className="flex items-center gap-2">
                  <div className="h-8 w-8 rounded-full bg-accent/20" />
                  <div>
                    <div className="text-sm font-medium text-white">{sample.title}</div>
                    <div className="text-xs text-muted">Just now</div>
                  </div>
                </div>
                <div className="text-text">{sample.content}</div>
              </div>
            )}
          </div>
        </CardContent>
      </Card>

      {/* Schedule and Cost */}
      <div className="grid gap-4 sm:grid-cols-2">
        <Card className="border-border bg-gradient-to-b from-[#1a1f40]/60 to-[#161a30]/60">
          <CardContent className="flex items-center gap-3 p-4">
            <div className="flex h-10 w-10 items-center justify-center rounded-lg bg-accent/10">
              <Clock size={18} className="text-accent" />
            </div>
            <div>
              <div className="text-sm font-medium text-white">Schedule</div>
              <div className="text-xs text-muted">{schedule.frequency}</div>
              <div className="text-xs text-accent">Next run: {schedule.nextRun}</div>
            </div>
          </CardContent>
        </Card>

        <Card className="border-border bg-gradient-to-b from-[#1a1f40]/60 to-[#161a30]/60">
          <CardContent className="flex items-center gap-3 p-4">
            <div className="flex h-10 w-10 items-center justify-center rounded-lg bg-accent/10">
              <Coins size={18} className="text-accent" />
            </div>
            <div>
              <div className="text-sm font-medium text-white">Cost</div>
              <div className="text-xs text-muted">{costPerRun}</div>
            </div>
          </CardContent>
        </Card>
      </div>

      {/* Approval Notice */}
      {requiresApproval && (
        <Card className="border-warning/30 bg-warning/5">
          <CardContent className="flex items-start gap-3 p-4">
            <AlertTriangle size={18} className="mt-0.5 text-warning" />
            <div className="space-y-1">
              <div className="text-sm font-medium text-warning">Approval Required</div>
              <p className="text-xs text-muted-foreground">
                This automation performs high-risk actions (sending emails, creating records).
                You&apos;ll need to approve each run before it executes.
              </p>
            </div>
          </CardContent>
        </Card>
      )}

      {/* Undo Path */}
      <div className="flex items-center justify-between">
        <p className="text-xs text-muted-foreground">
          You can pause or delete this automation anytime in Settings.
        </p>
        <div className="flex gap-2">
          <Button variant="default" onClick={onBack}>
            Back
          </Button>
          <Button
            variant="primary"
            onClick={handleActivate}
            disabled={isActivating}
          >
            Turn On
            <ChevronRight size={16} />
          </Button>
        </div>
      </div>
    </motion.div>
  );
}

export function PreviewScreenSkeleton() {
  return (
    <div className="space-y-6">
      <div className="flex items-center gap-4">
        <div className="h-9 w-9 rounded bg-surface-raised" />
        <div className="space-y-1.5">
          <div className="h-5 w-40 rounded bg-surface-raised" />
          <div className="h-3 w-32 rounded bg-surface-raised" />
        </div>
      </div>

      <Card className="border-border bg-gradient-to-b from-[#1a1f40]/60 to-[#161a30]/60">
        <div className="h-10 border-b border-border bg-accent/10" />
        <CardContent className="p-4">
          <div className="space-y-3">
            <div className="h-4 w-3/4 rounded bg-surface-raised" />
            <div className="h-4 w-full rounded bg-surface-raised" />
            <div className="h-4 w-5/6 rounded bg-surface-raised" />
            <div className="h-4 w-2/3 rounded bg-surface-raised" />
          </div>
        </CardContent>
      </Card>

      <div className="grid gap-4 sm:grid-cols-2">
        <div className="flex items-center gap-3 rounded-lg border border-border bg-[#1a1f40]/60 p-4">
          <div className="h-10 w-10 rounded-lg bg-surface-raised" />
          <div className="space-y-1.5">
            <div className="h-4 w-20 rounded bg-surface-raised" />
            <div className="h-3 w-32 rounded bg-surface-raised" />
          </div>
        </div>
        <div className="flex items-center gap-3 rounded-lg border border-border bg-[#1a1f40]/60 p-4">
          <div className="h-10 w-10 rounded-lg bg-surface-raised" />
          <div className="space-y-1.5">
            <div className="h-4 w-16 rounded bg-surface-raised" />
            <div className="h-3 w-24 rounded bg-surface-raised" />
          </div>
        </div>
      </div>

      <div className="flex items-center justify-between">
        <div className="h-3 w-48 rounded bg-surface-raised" />
        <div className="flex gap-2">
          <div className="h-9 w-20 rounded bg-surface-raised" />
          <div className="h-9 w-24 rounded bg-surface-raised" />
        </div>
      </div>
    </div>
  );
}

import { motion } from "framer-motion";
import { Check, Home, Settings, Plus, Smartphone } from "lucide-react";
import { Button } from "@/components/ui/button";
import { Card, CardContent } from "@/components/ui/card";

export interface ActivationSuccessProps {
  automationName: string;
  firstRunTime: string;
  destination: string;
  onAddToHome?: () => void;
  onViewAutomations?: () => void;
  onSetupAnother?: () => void;
}

export function ActivationSuccess({
  automationName,
  firstRunTime,
  destination,
  onAddToHome,
  onViewAutomations,
  onSetupAnother,
}: ActivationSuccessProps) {
  return (
    <motion.div
      initial={{ opacity: 0, scale: 0.95 }}
      animate={{ opacity: 1, scale: 1 }}
      transition={{ duration: 0.3 }}
      className="space-y-6"
    >
