      <div className="text-center">
        <motion.div
          initial={{ scale: 0 }}
          animate={{ scale: 1 }}
          transition={{ type: "spring", stiffness: 500, damping: 25, delay: 0.1 }}
          className="mx-auto mb-4 flex h-16 w-16 items-center justify-center rounded-full bg-success/20"
        >
          <Check size={32} className="text-success" />
        </motion.div>
        <h2 className="text-xl font-medium text-white">
          {automationName} is now active
        </h2>
      </div>

      {/* First Run Info */}
      <Card className="border-border bg-gradient-to-b from-[#1a1f40]/60 to-[#161a30]/60">
        <CardContent className="p-6 text-center">
          <p className="text-sm text-muted">Your first {automationName} will arrive</p>
          <p className="mt-2 text-lg font-medium text-white">{firstRunTime}</p>
          <p className="text-sm text-muted">at {destination}</p>
        </CardContent>
      </Card>

      {/* Next Steps */}
      <div className="space-y-3">
        <h3 className="text-sm font-medium text-muted">Next Steps</h3>

        <div className="grid gap-2">
          <Button
            variant="default"
            className="justify-start"
            onClick={onAddToHome}
          >
            <Smartphone size={18} />
            Add to Home Screen
            <span className="ml-auto text-xs text-muted-foreground">
