        <Home size={16} className="mt-0.5 text-muted" />
        <p className="text-xs text-muted-foreground">
          You can pause or delete this automation anytime in Settings → Automations.
        </p>
      </div>
    </motion.div>
  );
}

export function ActivationSuccessSkeleton() {
  return (
    <div className="space-y-6">
      <div className="text-center">
        <div className="mx-auto mb-4 h-16 w-16 rounded-full bg-surface-raised" />
        <div className="h-6 w-48 rounded bg-surface-raised" />
      </div>

      <Card className="border-border bg-gradient-to-b from-[#1a1f40]/60 to-[#161a30]/60">
        <CardContent className="space-y-2 p-6 text-center">
