import { Hono } from "hono";
import { z } from "zod";
import type { ApiRuntime } from "../services/runtime";

const previewParamsSchema = z.object({
  templateId: z.string().min(1),
});

// Fixture data for hero templates
const FIXTURES: Record<string, { sample: any; schedule: any; cost: string }> = {
  daily_command_brief: {
    sample: {
      title: "Your Daily Brief - April 6, 2026",
      content: `Good morning, Jon

TODAY'S PRIORITIES
1. Finish UX revamp implementation (2h focused work)
   - Create remaining components (PreviewScreen, ActivationSuccess)
   - Compose Home page with new components

2. Review PR #342 - Engine Adapter updates (30m)

3. 1:1 with Sarah (prep: 15m)

MEETINGS
• 10:00 AM — Sprint Planning (45m, Zoom)
  Prep: Review sprint board, update ticket statuses

• 2:00 PM — 1:1 with Sarah (30m, Google Meet)
  Topics: Design review, feedback on intent chips

CONFLICTS
⚠️ 3:00 PM call overlaps with focus block for implementation work
  Suggestion: Reschedule or protect 2-4pm as focus time

EMAIL DRAFTS (3 pending)
• Re: AutomationHub Timeline — suggested response drafted
• Q2 Planning Deck — suggested response drafted
• Design System Review — suggested response drafted`,
      type: "email" as const,
    },
    schedule: {
      frequency: "Daily at 7:00 AM",
      nextRun: "Tomorrow, April 7 at 7:00 AM",
      timezone: "America/Los_Angeles",
    },
    cost: "~$0.03 per run",
  },
  meeting_to_tasks: {
    sample: {
      title: "Tasks from Sprint Planning Meeting",
      content: `• Update sprint board with new ticket statuses (Priority: High, Due: Today)
• Review and merge PR #342 - Engine Adapter updates (Priority: High, Due: Tomorrow)
• Schedule design review session with Sarah (Priority: Medium, Due: This week)
• Document UX revamp components for team handoff (Priority: Medium, Due: Friday)
• Prepare demo for Friday's all-hands (Priority: Low, Due: Next week)`,
      type: "tasks" as const,
    },
    schedule: {
      frequency: "On-demand (manual trigger)",
      nextRun: "Next time you run this automation",
    },
    cost: "~$0.02 per run",
  },
  inbox_triage: {
    sample: {
      title: "Re: AutomationHub Timeline",
      content: `Hi team,

Thanks for the update on the UX revamp progress. The intent-first approach sounds like the right direction.

A few thoughts:
- Love the 6-step flow design — keeps cognitive load manageable
- Preview screen with explicit sample labeling is crucial for trust
- Nav reduction from 7 to 4 items should help with decision paralysis

Let's sync on Friday to review the implementation. I'd like to see how the activation success state handles the PWA "Add to Home" flow.

Best,
Sarah`,
      type: "email" as const,
    },
    schedule: {
      frequency: "On-demand (manual trigger)",
      nextRun: "Next time you run this automation",
    },
    cost: "~$0.02 per run",
  },
};

export function createPreviewRouter(_runtime: ApiRuntime): Hono {
  const app = new Hono();

  // GET /api/preview/:templateId
  // Returns preview data for a template including sample output, schedule, and cost
  app.get("/:templateId", async (c) => {
    const { templateId } = previewParamsSchema.parse({
      templateId: c.req.param("templateId"),
    });

    const fixture = FIXTURES[templateId];

    if (!fixture) {
      // Return a generic preview for unknown templates
      return c.json({
        sample: {
          title: `${templateId} Preview`,
          content: "This is a sample output. Configure the automation to see personalized results.",
          type: "notification" as const,
        },
        schedule: {
          frequency: "Configure during setup",
          nextRun: "After configuration",
        },
        cost: "Varies by configuration",
      });
    }

    return c.json({
      sample: fixture.sample,
      schedule: fixture.schedule,
      cost: fixture.cost,
    });
  });

  return app;
}

