import { createFileRoute, useNavigate } from "@tanstack/react-router";
import { useState } from "react";
import { motion } from "framer-motion";
import { useProfile } from "../contexts/profile-context";
import { useTemplates } from "../hooks/use-templates";
import { useIntegrations } from "../hooks/use-integrations";
import { Button } from "../components/ui/button";
import { IntentChips, type IntentChip } from "../components/IntentChips";
import { AutomationCard, type AutomationCardProps } from "../components/AutomationCard";

export const Route = createFileRoute("/")({
  component: HomePage,
});

function HomePage() {
  const navigate = useNavigate();
  const { profileId } = useProfile();
  const { data: templates = [] } = useTemplates();
  const { data: allIntegrations = [] } = useIntegrations();

  const [selectedIntent, setSelectedIntent] = useState<IntentChip | null>(null);

  // Check which tools are connected
  const connectedToolIds = allIntegrations
    .filter((i) => i.connected)
    .map((i) => i.connectorId);

  const isGmailConnected = connectedToolIds.some(
    (id) => id === "gmail" || id === "google-calendar"
  );
  const isCalendarConnected = connectedToolIds.some(
    (id) => id === "google-calendar"
  );

  // Recommended automations (hero templates)
  const recommendedAutomations: AutomationCardProps[] = [
    {
      id: "daily_command_brief",
      name: "Daily Brief",
      description: "Generates a structured daily plan from your calendar and emails",
      outcome: "Reads your calendar and emails, generates a structured daily plan with priorities and suggested email responses.",
      setupTime: "2 min",
      runFrequency: "Daily at 7:00 AM",
      costPerRun: "~$0.03",
      requiredTools: [
        { name: "Gmail", connected: isGmailConnected },
        { name: "Google Calendar", connected: isCalendarConnected },
      ],
      onConfigure: () => navigate({ to: "/automations", search: { template: "daily_command_brief" } }),
      variant: "recommended" as const,
    },
    {
      id: "meeting_to_tasks",
      name: "Meeting → Tasks",
      description: "Extract actionable tasks from meeting notes",
      outcome: "Analyzes meeting notes and extracts structured, actionable tasks with priorities and due dates.",
      setupTime: "2 min",
      runFrequency: "On-demand",
      costPerRun: "~$0.02",
      requiredTools: [
        { name: "Notion", connected: false },
        { name: "Todoist", connected: false },
      ],
      onConfigure: () => navigate({ to: "/automations", search: { template: "meeting_to_tasks" } }),
      variant: "recommended" as const,
    },
    {
      id: "inbox_triage",
      name: "Inbox Triage",
      description: "Draft responses to important emails",
      outcome: "Reviews your inbox, identifies important emails, and drafts thoughtful responses for your approval.",
      setupTime: "3 min",
      runFrequency: "On-demand",
      costPerRun: "~$0.02",
      requiredTools: [
        { name: "Gmail", connected: isGmailConnected },
      ],
      onConfigure: () => navigate({ to: "/automations", search: { template: "inbox_triage" } }),
      variant: "recommended" as const,
    },
  ];

  const handleIntentSelect = (intent: IntentChip) => {
    setSelectedIntent(intent);
    navigate({ to: "/automations", search: { template: intent.templateId } });
  };

  return (
    <motion.div
      initial={{ opacity: 0, y: 8 }}
      animate={{ opacity: 1, y: 0 }}
      transition={{ duration: 0.3 }}
      className="min-h-screen pb-16"
    >
      <div className="max-w-5xl mx-auto px-6 pt-8 space-y-8">
        {/* Header */}
        <div>
          <h1 className="text-2xl font-medium text-white">What would you like to automate?</h1>
          <p className="text-sm text-muted mt-1">
            Select an intent or browse recommended automations
          </p>
        </div>

        {/* Intent Chips */}
        <IntentChips onSelect={handleIntentSelect} />

        {/* Recommended Automations */}
        <div className="space-y-4">
          <div className="flex items-center gap-2">
            <h2 className="text-sm font-semibold text-muted uppercase tracking-wider">
              Recommended
            </h2>
          </div>
          <div className="grid gap-4">
            {recommendedAutomations.map((automation, index) => (
              <motion.div
                key={automation.id}
                initial={{ opacity: 0, y: 8 }}
                animate={{ opacity: 1, y: 0 }}
                transition={{ delay: index * 0.1 }}
              >
                <AutomationCard {...automation} />
              </motion.div>
            ))}
          </div>
        </div>

        {/* Browse All Link */}
        <div className="flex justify-center pt-4">
          <Button
            variant="link"
            onClick={() => navigate({ to: "/automations" })}
            className="text-muted hover:text-white"
          >
            Browse all automations →
          </Button>
        </div>
      </div>
    </motion.div>
  );
}

