import { createFileRoute, useNavigate, useSearch } from "@tanstack/react-router";
import { useState, useEffect } from "react";
import { motion } from "framer-motion";
import { ArrowLeft } from "lucide-react";
import { useProfile } from "../contexts/profile-context";
import { useTemplates } from "../hooks/use-templates";
import { useIntegrations } from "../hooks/use-integrations";
import { Button } from "../components/ui/button";
import { AutomationCard } from "../components/AutomationCard";
import { PreviewScreen } from "../components/PreviewScreen";
import { ActivationSuccess } from "../components/ActivationSuccess";
import { LIBRARY } from "../lib/constants";

export const Route = createFileRoute("/automations")({
  component: AutomationsPage,
});

type View = "list" | "detail" | "preview" | "success";

function AutomationsPage() {
  const navigate = useNavigate();
  const { profileId } = useProfile();
  const { data: templates = [] } = useTemplates();
  const { data: allIntegrations = [] } = useIntegrations();
  const search = useSearch({ from: "/automations" }) as { template?: string };

  const [view, setView] = useState<View>("list");
  const [selectedTemplateId, setSelectedTemplateId] = useState<string | null>(null);

  // If template query param exists, go directly to detail view
  useEffect(() => {
    if (search?.template) {
      setSelectedTemplateId(search.template);
      setView("detail");
    }
  }, [search?.template]);

  const connectedToolIds = allIntegrations
    .filter((i) => i.connected)
    .map((i) => i.id);

  const isToolConnected = (toolName: string) => {
    return connectedToolIds.some((id) => id.toLowerCase().includes(toolName.toLowerCase()));
  };

  const selectedTemplate = LIBRARY.find((t) => t.id === selectedTemplateId);

  const handleBack = () => {
    if (view === "detail") {
      setView("list");
      setSelectedTemplateId(null);
    } else if (view === "preview") {
      setView("detail");
    } else if (view === "success") {
      setView("list");
    }
  };

  const handleConfigure = () => {
    setView("preview");
  };

  const handleActivate = () => {
    setView("success");
  };

  return (
    <motion.div
      initial={{ opacity: 0, y: 8 }}
      animate={{ opacity: 1, y: 0 }}
      transition={{ duration: 0.3 }}
      className="min-h-screen pb-16"
    >
      <div className="max-w-4xl mx-auto px-6 pt-8">
        {view !== "list" && (
          <Button variant="ghost" size="sm" onClick={handleBack} className="mb-6">
            <ArrowLeft size={16} className="mr-2" />
            Back
          </Button>
        )}

        {view === "list" && (
          <div className="space-y-6">
            <div>
              <h1 className="text-2xl font-medium text-white">Browse Automations</h1>
              <p className="text-sm text-muted mt-1">
                Discover and install automation templates
              </p>
            </div>

            <div className="grid gap-4">
              {LIBRARY.map((template, index) => (
                <motion.div
                  key={template.id}
                  initial={{ opacity: 0, y: 8 }}
                  animate={{ opacity: 1, y: 0 }}
                  transition={{ delay: index * 0.05 }}
                >
                  <AutomationCard
                    id={template.id}
                    name={template.name}
                    description={template.description}
                    outcome={template.description}
                    setupTime="2 min"
                    runFrequency="Configurable"
                    costPerRun="~$0.02"
                    requiredTools={template.connectors.map((c) => ({
                      name: c,
                      connected: isToolConnected(c),
                    }))}
                    onConfigure={() => {
                      setSelectedTemplateId(template.id);
                      setView("detail");
                    }}
                    variant="recommended"
                  />
                </motion.div>
              ))}
            </div>
          </div>
        )}

        {view === "detail" && selectedTemplate && (
          <div className="space-y-6">
            <div>
              <h1 className="text-2xl font-medium text-white">{selectedTemplate.name}</h1>
              <p className="text-sm text-muted mt-1">{selectedTemplate.description}</p>
            </div>

            <div className="space-y-4">
              <div>
                <h3 className="text-sm font-semibold text-muted uppercase tracking-wider mb-2">
                  What It Does
                </h3>
                <p className="text-text">{selectedTemplate.description}</p>
              </div>

              <div className="grid grid-cols-2 gap-4">
                <div>
                  <h3 className="text-sm font-semibold text-muted uppercase tracking-wider mb-2">
                    Setup Time
                  </h3>
                  <p className="text-white">~2 minutes</p>
                </div>
                <div>
                  <h3 className="text-sm font-semibold text-muted uppercase tracking-wider mb-2">
                    Required Tools
                  </h3>
                  <div className="flex flex-wrap gap-2">
                    {selectedTemplate.connectors.map((connector) => (
                      <span
                        key={connector}
                        className={`text-xs px-2 py-1 rounded ${
                          isToolConnected(connector)
                            ? "bg-success/20 text-success"
                            : "bg-muted/20 text-muted"
                        }`}
                      >
                        {isToolConnected(connector) ? "✓" : "○"} {connector}
                      </span>
                    ))}
                  </div>
                </div>
              </div>

              <div className="pt-4">
                <Button
                  variant="primary"
                  className="w-full"
                  onClick={handleConfigure}
                  disabled={!selectedTemplate.connectors.every((c) => isToolConnected(c))}
                >
                  {selectedTemplate.connectors.every((c) => isToolConnected(c))
                    ? "Continue to Configuration"
                    : "Connect Required Tools First"}
                </Button>
              </div>
            </div>
          </div>
        )}

        {view === "preview" && selectedTemplate && (
          <PreviewScreen
            automationName={selectedTemplate.name}
            sample={{
              title: `${selectedTemplate.name} Sample`,
              content: "This is a preview sample. Actual output will be generated based on your configuration.",
              type: "notification",
            }}
            schedule={{
              frequency: "Daily at 7:00 AM",
              nextRun: "Tomorrow at 7:00 AM",
            }}
            costPerRun="~$0.03"
            requiresApproval={true}
            onBack={handleBack}
            onActivate={handleActivate}
          />
        )}

        {view === "success" && selectedTemplate && (
          <ActivationSuccess
            automationName={selectedTemplate.name}
            firstRunTime="Tomorrow at 7:00 AM"
            destination="your email"
            onViewAutomations={() => navigate({ to: "/automations" })}
            onSetupAnother={() => {
              setView("list");
              setSelectedTemplateId(null);
            }}
          />
        )}
      </div>
    </motion.div>
  );
}

import { createFileRoute } from "@tanstack/react-router";
import { motion } from "framer-motion";
import { Activity as ActivityIcon } from "lucide-react";
import { useProfile } from "../contexts/profile-context";
import { useRuns } from "../hooks/use-runs";
import { useApprovals } from "../hooks/use-approvals";
import { Badge } from "../components/ui/badge";

export const Route = createFileRoute("/activity")({
  component: ActivityPage,
});

function ActivityPage() {
  const { profileId } = useProfile();
  const { data: runs = [] } = useRuns(profileId);
  const { data: approvals = [] } = useApprovals();

  return (
    <motion.div
      initial={{ opacity: 0, y: 8 }}
      animate={{ opacity: 1, y: 0 }}
      transition={{ duration: 0.3 }}
      className="min-h-screen pb-16"
    >
      <div className="max-w-5xl mx-auto px-6 pt-8 space-y-8">
        <div>
          <h1 className="text-2xl font-medium text-white">Activity</h1>
          <p className="text-sm text-muted mt-1">
            View run history and manage approvals
          </p>
        </div>

        {/* Pending Approvals */}
        {approvals.length > 0 && (
          <div className="space-y-4">
            <div className="flex items-center gap-2">
              <ActivityIcon size={18} className="text-amber-500" />
              <h2 className="text-sm font-semibold text-muted uppercase tracking-wider">
                Pending Approvals
              </h2>
              <Badge variant="warning">{approvals.length}</Badge>
            </div>
            <div className="space-y-2">
              {approvals.map((approval) => (
                <div
                  key={approval.id}
                  className="p-4 rounded-lg border border-border bg-[#161a30]/60"
                >
                  <div className="flex items-center justify-between">
                    <div>
                      <p className="text-sm font-medium text-white">
                        Approval required
                      </p>
                      <p className="text-xs text-muted">
                        Run #{approval.runId.slice(0, 8)}
                      </p>
                    </div>
                    <Badge variant="warning">Action Required</Badge>
                  </div>
                </div>
              ))}
            </div>
          </div>
        )}

        {/* Recent Runs */}
        <div className="space-y-4">
          <div className="flex items-center gap-2">
            <ActivityIcon size={18} className="text-accent" />
            <h2 className="text-sm font-semibold text-muted uppercase tracking-wider">
              Recent Runs
            </h2>
          </div>
          <div className="space-y-2">
            {runs.length === 0 ? (
              <div className="text-center py-8">
                <p className="text-sm text-muted">No runs yet</p>
                <p className="text-xs text-muted/60 mt-1">
                  Start an automation to see activity here
                </p>
              </div>
            ) : (
              runs.slice(0, 10).map((run) => (
                <div
                  key={run.id}
                  className="p-4 rounded-lg border border-border bg-[#161a30]/60"
                >
                  <div className="flex items-center justify-between">
                    <div>
                      <p className="text-sm font-medium text-white">
                        {run.templateId}
                      </p>
                      <p className="text-xs text-muted">
                        {new Date(run.startedAt).toLocaleString()}
                      </p>
                    </div>
                    <div className="flex items-center gap-2">
                      <span
                        className={`w-2 h-2 rounded-full ${
                          run.status === "completed"
                            ? "bg-success"
                            : run.status === "failed"
                            ? "bg-error"
                            : "bg-warning"
                        }`}
                      />
                      <span className="text-xs text-muted capitalize">
                        {run.status}
                      </span>
                    </div>
                  </div>
                </div>
              ))
            )}
          </div>
        </div>
      </div>
    </motion.div>
  );
}

