  toolName,
  toolDisplayName,
  whyNeeded,
  onBack,
  onConnected,
}: ConnectToolsProps) {
  const connectOAuth = useOAuthConnect();

  const handleConnect = () => {
    connectOAuth(toolName as "google-calendar" | "gmail", () => {
      // OAuth completed in popup, user will return to this screen
      // They need to manually confirm with "I Connected It"
    });
  };

  return (
    <motion.div
      initial={{ opacity: 0, y: 8 }}
      animate={{ opacity: 1, y: 0 }}
      transition={{ duration: 0.3 }}
      className="space-y-6"
    >
      <div>
        <h1 className="text-2xl font-medium text-white">
          Connect {toolDisplayName}
        </h1>
        <p className="text-sm text-muted mt-1">
          This automation needs {toolDisplayName} to:
        </p>
      </div>

      <div className="space-y-3">
        {whyNeeded.map((reason, index) => (
          <div key={index} className="flex items-start gap-3">
            <div className="w-1.5 h-1.5 rounded-full bg-accent mt-2 flex-shrink-0" />
            <p className="text-text text-sm">{reason}</p>
          </div>
        ))}
      </div>

      <div className="bg-[#161a30]/60 border border-border rounded-lg p-6 space-y-4">
        <Button
          variant="primary"
          className="w-full"
          onClick={handleConnect}
        >
          <ExternalLink size={16} className="mr-2" />
          Connect with Google
        </Button>

        <div className="flex items-start gap-3">
          <div className="text-amber-500 mt-0.5">
            <span className="text-xs">ℹ️</span>
          </div>
          <p className="text-xs text-muted/80">
            You'll be redirected to Google to authorize.
            Come back here after you complete authorization.
          </p>
        </div>

        <div className="pt-2">
          <Button
            variant="secondary"
            className="w-full border border-success/30 bg-success/10 text-success hover:bg-success/20"
            onClick={onConnected}
          >
            <Check size={16} className="mr-2" />
            I Connected It
          </Button>
        </div>
      </div>

      <Button
        variant="ghost"
        size="sm"
        onClick={onBack}
        className="w-full"
      >
        <ArrowLeft size={16} className="mr-2" />
        Back to Configuration
      </Button>
    </motion.div>
  );
}

import { useState } from "react";
import { motion } from "framer-motion";
import { ArrowLeft } from "lucide-react";
import { Button } from "./ui/button";
import { Label } from "./ui/label";
import { Select } from "./ui/select";

interface ConfigurationField {
  id: string;
  label: string;
  type: "time" | "dropdown" | "checkbox" | "text";
  options?: string[];
  defaultValue: string | boolean;
  placeholder?: string;
}

interface ConfigurationProps {
  automationName: string;
  fields: ConfigurationField[];
  stepNumber?: number;
  totalSteps?: number;
  onBack: () => void;
  onPreview: (values: Record<string, string | boolean>) => void;
}

export function Configuration({
  automationName,
  fields,
  stepNumber = 4,
  totalSteps = 6,
  onBack,
  onPreview,
}: ConfigurationProps) {
  const [values, setValues] = useState<Record<string, string | boolean>>(
    fields.reduce((acc, field) => {
      acc[field.id] = field.defaultValue;
      return acc;
    }, {} as Record<string, string | boolean>)
  );

  const allValid = Object.values(values).every(
    (v) => v !== undefined && v !== null && v !== ""
  );

  const handleChange = (id: string, value: string | boolean) => {
    setValues((prev) => ({ ...prev, [id]: value }));
  };

  return (
    <motion.div
      initial={{ opacity: 0, y: 8 }}
      animate={{ opacity: 1, y: 0 }}
      transition={{ duration: 0.3 }}
      className="space-y-6"
    >
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-2xl font-medium text-white">
            Configure {automationName}
          </h1>
          <p className="text-sm text-muted mt-1">
            Step {stepNumber} of {totalSteps}
          </p>
        </div>
        <div className="flex items-center gap-2">
          {Array.from({ length: totalSteps }).map((_, i) => (
            <div
              key={i}
              className={`w-2 h-2 rounded-full ${
                i + 1 <= stepNumber ? "bg-accent" : "bg-muted"
              }`}
            />
          ))}
        </div>
      </div>

      <div className="space-y-5">
        {fields.map((field) => (
          <div key={field.id} className="space-y-2">
            <Label className="text-white">{field.label}</Label>

            {field.type === "time" && (
              <Select
                value={values[field.id] as string}
                onValueChange={(v) => handleChange(field.id, v)}
                options={field.options || []}
              />
            )}

            {field.type === "dropdown" && (
              <Select
                value={values[field.id] as string}
                onValueChange={(v) => handleChange(field.id, v)}
                options={field.options || []}
              />
            )}

            {field.type === "checkbox" && (
              <div className="space-y-2">
                {(field.options || []).map((option) => {
                  const isChecked = Array.isArray(values[field.id])
                    ? (values[field.id] as string[]).includes(option)
                    : false;
                  return (
                    <label
                      key={option}
                      className="flex items-center gap-3 cursor-pointer"
                    >
                      <input
                        type="checkbox"
                        checked={isChecked}
                        onChange={(e) => {
                          const current = Array.isArray(values[field.id])
                            ? (values[field.id] as string[])
                            : [];
                          const newValue = e.target.checked
                            ? [...current, option]
                            : current.filter((o) => o !== option);
                          handleChange(field.id, newValue);
                        }}
                        className="w-4 h-4 rounded border-border bg-[#0f1117] text-accent focus:ring-accent"
                      />
                      <span className="text-sm text-text">{option}</span>
                    </label>
                  );
                })}
              </div>
            )}

            {field.type === "text" && (
              <input
                type="text"
                value={values[field.id] as string}
                onChange={(e) => handleChange(field.id, e.target.value)}
                placeholder={field.placeholder}
                className="w-full px-3 py-2 rounded-lg border border-border bg-[#0f1117] text-white placeholder:text-muted/60 focus:border-accent focus:outline-none"
              />
            )}
          </div>
        ))}
      </div>

      <div className="flex gap-3 pt-4">
        <Button variant="ghost" onClick={onBack} className="flex-1">
          <ArrowLeft size={16} className="mr-2" />
          Back
        </Button>
        <Button
          variant="primary"
          onClick={() => onPreview(values)}
          disabled={!allValid}
          className="flex-1"
        >
          Preview
        </Button>
      </div>
    </motion.div>
  );
}

