import { handle } from "hono/vercel";
import { N8nEngineAdapter } from "@openclaw/engine-adapter";
import "dotenv/config";
import { createApp } from "../src/app";
import { createRuntime } from "../src/services/runtime";
import { migrateDatabase } from "../src/db/migrate";

// Initialize runtime and app for serverless
let cachedApp: ReturnType<typeof createApp> | null = null;
let cachedRuntime: ReturnType<typeof createRuntime> | null = null;

async function getApp() {
  if (cachedApp && cachedRuntime) {
    return { app: cachedApp, runtime: cachedRuntime };
  }

  // Initialize database and runtime
  await migrateDatabase();
  const runtime = await createRuntime();
  const app = createApp(runtime);

  cachedRuntime = runtime;
  cachedApp = app;

  return { app, runtime };
}

// Export handlers for Vercel serverless functions
export const GET = handleRequest();
export const POST = handleRequest();
export const PUT = handleRequest();
export const DELETE = handleRequest();
export const PATCH = handleRequest();
export const OPTIONS = handleRequest();

function handleRequest() {
  return async (request: Request) => {
    try {
      const { app } = await getApp();
      return app.fetch(request);
    } catch (error) {
      console.error("API request failed:", error);
      return new Response(
        JSON.stringify({
          error: "Internal server error",
          code: "INTERNAL_ERROR",
          details: error instanceof Error ? error.message : String(error)
        }),
        {
          status: 500,
          headers: { "Content-Type": "application/json" }
        }
      );
    }
  };
}

